import requests
import json
from pydantic import BaseModel, Field


class Tools:
    class Valves(BaseModel):
        COINGECKO_API_KEY: str = Field(
            default="",
            description="Optional CoinGecko API key from coingecko.com/api (free tier works without)",
        )

    def __init__(self):
        self.valves = self.Valves()
        self.base = "https://api.coingecko.com/api/v3"

    def _get(self, endpoint: str, params: dict = {}) -> any:
        headers = {}
        if self.valves.COINGECKO_API_KEY:
            headers["x-cg-demo-api-key"] = self.valves.COINGECKO_API_KEY
        res = requests.get(f"{self.base}/{endpoint}", params=params, headers=headers)
        return res.json()

    def get_coin_price(self, coin_ids: str, currencies: str = "usd") -> str:
        """
        Get price for one or more coins.
        coin_ids: comma separated e.g. 'bitcoin,ethereum,solana,binancecoin,ripple'
        currencies: comma separated e.g. 'usd,eur,gbp,btc'
        """
        try:
            data = self._get(
                "simple/price",
                {
                    "ids": coin_ids,
                    "vs_currencies": currencies,
                    "include_market_cap": True,
                    "include_24hr_vol": True,
                    "include_24hr_change": True,
                    "include_last_updated_at": True,
                },
            )
            return json.dumps(data)
        except Exception as e:
            return f"Error: {e}"

    def get_top_coins(self, limit: int = 20, currency: str = "usd") -> str:
        """Get top N coins by market cap with full market data."""
        try:
            data = self._get(
                "coins/markets",
                {
                    "vs_currency": currency,
                    "order": "market_cap_desc",
                    "per_page": limit,
                    "page": 1,
                    "price_change_percentage": "1h,24h,7d,30d",
                },
            )
            return json.dumps(
                [
                    {
                        "rank": c["market_cap_rank"],
                        "id": c["id"],
                        "name": c["name"],
                        "symbol": c["symbol"].upper(),
                        "price": c["current_price"],
                        "market_cap": c["market_cap"],
                        "fully_diluted_valuation": c["fully_diluted_valuation"],
                        "total_volume": c["total_volume"],
                        "high_24h": c["high_24h"],
                        "low_24h": c["low_24h"],
                        "change_1h_%": c.get("price_change_percentage_1h_in_currency"),
                        "change_24h_%": c["price_change_percentage_24h"],
                        "change_7d_%": c.get("price_change_percentage_7d_in_currency"),
                        "change_30d_%": c.get(
                            "price_change_percentage_30d_in_currency"
                        ),
                        "circulating_supply": c["circulating_supply"],
                        "total_supply": c["total_supply"],
                        "max_supply": c["max_supply"],
                        "ath": c["ath"],
                        "ath_change_%": c["ath_change_percentage"],
                        "ath_date": c["ath_date"],
                        "atl": c["atl"],
                        "atl_change_%": c["atl_change_percentage"],
                    }
                    for c in data
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_coin_details(self, coin_id: str) -> str:
        """
        Get complete data for a specific coin.
        coin_id: bitcoin, ethereum, solana, binancecoin, ripple, cardano, dogecoin, avalanche-2
        """
        try:
            data = self._get(
                f"coins/{coin_id}",
                {
                    "localization": False,
                    "tickers": False,
                    "market_data": True,
                    "community_data": True,
                    "developer_data": True,
                },
            )
            market = data.get("market_data", {})
            community = data.get("community_data", {})
            developer = data.get("developer_data", {})
            return json.dumps(
                {
                    "id": data.get("id"),
                    "name": data.get("name"),
                    "symbol": data.get("symbol"),
                    "description": data.get("description", {}).get("en", "")[:500],
                    "website": data.get("links", {}).get("homepage", [None])[0],
                    "whitepaper": data.get("links", {}).get("whitepaper"),
                    "genesis_date": data.get("genesis_date"),
                    "categories": data.get("categories"),
                    "hashing_algorithm": data.get("hashing_algorithm"),
                    "country_origin": data.get("country_origin"),
                    # Market
                    "price_usd": market.get("current_price", {}).get("usd"),
                    "market_cap_usd": market.get("market_cap", {}).get("usd"),
                    "market_cap_rank": market.get("market_cap_rank"),
                    "fdv": market.get("fully_diluted_valuation", {}).get("usd"),
                    "total_volume": market.get("total_volume", {}).get("usd"),
                    "high_24h": market.get("high_24h", {}).get("usd"),
                    "low_24h": market.get("low_24h", {}).get("usd"),
                    "change_24h_%": market.get("price_change_percentage_24h"),
                    "change_7d_%": market.get("price_change_percentage_7d"),
                    "change_14d_%": market.get("price_change_percentage_14d"),
                    "change_30d_%": market.get("price_change_percentage_30d"),
                    "change_60d_%": market.get("price_change_percentage_60d"),
                    "change_1y_%": market.get("price_change_percentage_1y"),
                    "ath": market.get("ath", {}).get("usd"),
                    "ath_date": market.get("ath_date", {}).get("usd"),
                    "ath_change_%": market.get("ath_change_percentage", {}).get("usd"),
                    "atl": market.get("atl", {}).get("usd"),
                    "atl_date": market.get("atl_date", {}).get("usd"),
                    "circulating_supply": market.get("circulating_supply"),
                    "total_supply": market.get("total_supply"),
                    "max_supply": market.get("max_supply"),
                    # Community
                    "twitter_followers": community.get("twitter_followers"),
                    "reddit_subscribers": community.get("reddit_subscribers"),
                    "telegram_users": community.get("telegram_channel_user_count"),
                    # Developer
                    "github_stars": developer.get("stars"),
                    "github_forks": developer.get("forks"),
                    "github_commits_4w": developer.get("commit_count_4_weeks"),
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_coin_history(
        self, coin_id: str, days: int = 30, currency: str = "usd"
    ) -> str:
        """
        Get historical price, market cap and volume data.
        coin_id: bitcoin, ethereum, solana etc.
        days: 1, 7, 14, 30, 90, 180, 365, max
        """
        try:
            data = self._get(
                f"coins/{coin_id}/market_chart",
                {
                    "vs_currency": currency,
                    "days": days,
                },
            )
            prices = data.get("prices", [])
            volumes = data.get("total_volumes", [])
            market_caps = data.get("market_caps", [])
            return json.dumps(
                [
                    {
                        "timestamp": prices[i][0],
                        "price": round(prices[i][1], 4),
                        "market_cap": (
                            market_caps[i][1] if i < len(market_caps) else None
                        ),
                        "volume": volumes[i][1] if i < len(volumes) else None,
                    }
                    for i in range(0, len(prices), max(1, len(prices) // 30))
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_global_market(self) -> str:
        """Get global crypto market stats: total market cap, BTC/ETH dominance, DeFi, volume."""
        try:
            data = self._get("global").get("data", {})
            return json.dumps(
                {
                    "total_market_cap_usd": data.get("total_market_cap", {}).get("usd"),
                    "total_volume_24h_usd": data.get("total_volume", {}).get("usd"),
                    "btc_dominance_%": round(
                        data.get("market_cap_percentage", {}).get("btc", 0), 2
                    ),
                    "eth_dominance_%": round(
                        data.get("market_cap_percentage", {}).get("eth", 0), 2
                    ),
                    "active_cryptocurrencies": data.get("active_cryptocurrencies"),
                    "markets": data.get("markets"),
                    "defi_volume_24h": data.get("defi_volume_24h"),
                    "defi_dominance_%": data.get("defi_dominance"),
                    "top_defi_coin": data.get("top_defi_coin_name"),
                    "market_cap_change_24h_%": data.get(
                        "market_cap_change_percentage_24h_usd"
                    ),
                    "updated_at": data.get("updated_at"),
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_defi_overview(self) -> str:
        """Get global DeFi market overview: DeFi market cap, volume, ETH dominance."""
        try:
            data = self._get("global/decentralized_finance_defi")
            return json.dumps(data.get("data", {}))
        except Exception as e:
            return f"Error: {e}"

    def get_trending_coins(self) -> str:
        """Get top trending coins, NFTs and categories on CoinGecko right now."""
        try:
            data = self._get("search/trending")
            return json.dumps(
                {
                    "trending_coins": [
                        {
                            "name": c["item"]["name"],
                            "symbol": c["item"]["symbol"],
                            "rank": c["item"]["market_cap_rank"],
                            "price_usd": c["item"].get("data", {}).get("price"),
                            "change_24h_%": c["item"]
                            .get("data", {})
                            .get("price_change_percentage_24h", {})
                            .get("usd"),
                        }
                        for c in data.get("coins", [])
                    ],
                    "trending_nfts": [
                        {
                            "name": n["name"],
                            "symbol": n["symbol"],
                        }
                        for n in data.get("nfts", [])
                    ],
                    "trending_categories": [
                        {
                            "name": cat["name"],
                            "change_1h_%": cat.get("data", {}).get(
                                "market_cap_change_percentage_1h"
                            ),
                        }
                        for cat in data.get("categories", [])
                    ],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_exchanges(self, limit: int = 20) -> str:
        """Get top crypto exchanges by trading volume."""
        try:
            data = self._get("exchanges", {"per_page": limit, "page": 1})
            return json.dumps(
                [
                    {
                        "rank": e.get("trust_score_rank"),
                        "name": e.get("name"),
                        "country": e.get("country"),
                        "volume_24h_btc": e.get("trade_volume_24h_normalized"),
                        "trust_score": e.get("trust_score"),
                        "year_established": e.get("year_established"),
                        "url": e.get("url"),
                    }
                    for e in data
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_coin_categories(self) -> str:
        """Get all crypto categories with market cap and performance data."""
        try:
            data = self._get("coins/categories", {"order": "market_cap_desc"})
            return json.dumps(
                [
                    {
                        "name": c["name"],
                        "market_cap": c["market_cap"],
                        "change_24h_%": c["market_cap_change_24h"],
                        "volume_24h": c["volume_24h"],
                        "top_3_coins": c["top_3_coins"],
                    }
                    for c in (data[:20] if data else [])
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def search_coin(self, query: str) -> str:
        """Search for a coin, exchange or category by name. e.g. 'bitcoin', 'binance', 'defi'"""
        try:
            data = self._get("search", {"query": query})
            return json.dumps(
                {
                    "coins": [
                        {
                            "id": c["id"],
                            "name": c["name"],
                            "symbol": c["symbol"],
                            "rank": c["market_cap_rank"],
                        }
                        for c in data.get("coins", [])[:10]
                    ],
                    "exchanges": [
                        {"id": e["id"], "name": e["name"]}
                        for e in data.get("exchanges", [])[:5]
                    ],
                    "categories": [
                        {"name": cat["name"]} for cat in data.get("categories", [])[:5]
                    ],
                }
            )
        except Exception as e:
            return f"Error: {e}"

    def get_coin_ohlc(self, coin_id: str, days: int = 14, currency: str = "usd") -> str:
        """
        Get OHLC candlestick data for a coin.
        days: 1, 7, 14, 30, 90, 180, 365
        """
        try:
            data = self._get(
                f"coins/{coin_id}/ohlc", {"vs_currency": currency, "days": days}
            )
            return json.dumps(
                [
                    {
                        "timestamp": d[0],
                        "open": d[1],
                        "high": d[2],
                        "low": d[3],
                        "close": d[4],
                    }
                    for d in data
                ]
            )
        except Exception as e:
            return f"Error: {e}"

    def get_supported_currencies(self) -> str:
        """Get all supported vs_currencies on CoinGecko."""
        try:
            return json.dumps(self._get("simple/supported_vs_currencies"))
        except Exception as e:
            return f"Error: {e}"

    def compare_coins(self, coin_ids: str, currency: str = "usd") -> str:
        """
        Compare multiple coins side by side.
        coin_ids: comma separated e.g. 'bitcoin,ethereum,solana,cardano'
        """
        try:
            data = self._get(
                "coins/markets",
                {
                    "vs_currency": currency,
                    "ids": coin_ids,
                    "order": "market_cap_desc",
                    "price_change_percentage": "1h,24h,7d",
                },
            )
            return json.dumps(
                [
                    {
                        "name": c["name"],
                        "symbol": c["symbol"].upper(),
                        "price": c["current_price"],
                        "market_cap": c["market_cap"],
                        "rank": c["market_cap_rank"],
                        "change_1h_%": c.get("price_change_percentage_1h_in_currency"),
                        "change_24h_%": c["price_change_percentage_24h"],
                        "change_7d_%": c.get("price_change_percentage_7d_in_currency"),
                        "ath": c["ath"],
                        "ath_change_%": c["ath_change_percentage"],
                    }
                    for c in data
                ]
            )
        except Exception as e:
            return f"Error: {e}"
